/* eslint-disable */
declare module "*.vue" {
  import type { DefineComponent } from "vue";
  const component: DefineComponent<{}, {}, any>;
  export default component;
}

declare module "*.jpg" {
  const src: string;
  export default src;
}

declare module "*.jpeg" {
  const src: string;
  export default src;
}

declare module "*.png" {
  const src: string;
  export default src;
}

declare module "*.webp" {
  const src: string;
  export default src;
}

/** @deprecated 优先使用 `@/api` 的 ApiResponse */
interface ResponseBody {
  code: number | string;
  success: boolean;
  message: string;
  type?: string;
  data?: any;
}
